import sys

class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Solution:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word: str) -> bool:
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

    def startsWith(self, prefix: str) -> bool:
        node = self.root
        for char in prefix:
            if char not in node.children:
                return False
            node = node.children[char]
        return True

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        sol = Solution()
        for _ in range(n):
            op = next(it)
            word = next(it)
            if op == 'insert':
                sol.insert(word)
            elif op == 'search':
                print(sol.search(word))
            elif op == 'startsWith':
                print(sol.startsWith(word))
    except StopIteration:
        sys.exit(0)

