#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TrieNode {
    unordered_map<char, TrieNode*> children;
    bool is_end_of_word;
    TrieNode() : is_end_of_word(false) {}
};

class Solution {
public:
    Solution() : root(new TrieNode()) {}
    ~Solution() { destroy(root); }

    void insert(string word) {
        TrieNode* node = root;
        for (char c : word) {
            if (node->children.find(c) == node->children.end()) {
                node->children[c] = new TrieNode();
            }
            node = node->children[c];
        }
        node->is_end_of_word = true;
    }

    bool search(string word) {
        TrieNode* node = root;
        for (char c : word) {
            if (node->children.find(c) == node->children.end()) {
                return false;
            }
            node = node->children[c];
        }
        return node->is_end_of_word;
    }

    bool startsWith(string prefix) {
        TrieNode* node = root;
        for (char c : prefix) {
            if (node->children.find(c) == node->children.end()) {
                return false;
            }
            node = node->children[c];
        }
        return true;
    }

private:
    TrieNode* root;

    void destroy(TrieNode* node) {
        if (!node) return;
        for (auto& child : node->children) {
            destroy(child.second);
        }
        delete node;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    Solution sol;
    for (int i = 0; i < n; i++) {
        string op;
        cin >> op;
        string word;
        cin >> word;
        if (op == "insert") {
            sol.insert(word);
        } else if (op == "search") {
            cout << boolalpha << sol.search(word) << "\n";
        } else if (op == "startsWith") {
            cout << boolalpha << sol.startsWith(word) << "\n";
        }
    }
    return 0;
}
